@Composable
fun EditItemDialog(
    item: InventoryItem,
    onConfirm: (InventoryItem) -> Unit,
    onCancel: () -> Unit
) {
    // maintain state for editable fields
    val name = item.name
    var stock by remember { mutableStateOf(item.stock.toString()) }
    var price by remember { mutableStateOf(item.price.toString()) }

    AlertDialog(
        onDismissRequest = onCancel,
        title = { Text(text = "Edit Item") },
        text = {
            Column {
                TextField(
                    value = stock,
                    onValueChange = { newText ->
                        stock = newText
                    },
                    supportingText = { Text("Stock") },
                    keyboardOptions = KeyboardOptions(
                        keyboardType = KeyboardType.Number,
                        imeAction = ImeAction.Done
                    ),
                    keyboardActions = KeyboardActions(onDone = { })
                )
                TextField(
                    value = price,
                    onValueChange = { newText ->
                        price = newText
                    },
                    supportingText = { Text("Price") },
                    keyboardOptions = KeyboardOptions(
                        keyboardType = KeyboardType.Number,
                        imeAction = ImeAction.Done
                    ),
                    keyboardActions = KeyboardActions(onDone = { })
                )
            }
        },
        confirmButton = {
            Button(
                onClick = {
                    val updatedItem = item.copy(
                        name = name,
                        stock = stock.toIntOrNull(),
                        price = price.toDoubleOrNull()
                    )
                    onConfirm(updatedItem)
                }
            ) {
                Text("Confirm")
            }
        },
        dismissButton = {
            Button(onClick = onCancel) {
                Text("Cancel")
            }
        }
    )
}

